module div_8bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    reg [7:0] dividend_abs;
    reg [7:0] divisor_abs;
    reg [15:0] SR;
    reg [3:0] cnt;
    reg [7:0] NEG_DIVISOR;
    reg start_cnt;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dividend_abs <= 0;
            divisor_abs <= 0;
            SR <= 0;
            cnt <= 0;
            NEG_DIVISOR <= 0;
            start_cnt <= 0;
            res_valid <= 0;
            result <= 0;
        end else if (opn_valid && !res_valid) begin
            dividend_abs <= (sign && dividend[7]) ? ~dividend + 1 : dividend;
            divisor_abs <= (sign && divisor[7]) ? ~divisor + 1 : divisor;
            SR <= {dividend_abs, 1'b0};
            cnt <= 4'b0001;
            NEG_DIVISOR <= ~divisor_abs + 1;
            start_cnt <= 1;
            res_valid <= 1;
        end else if (start_cnt) begin
            if (cnt[3]) begin
                cnt <= 0;
                NEG_DIVISOR <= {divisor_abs, 1'b0};
                SR <= {SR[14:0], 1'b0};
            end else begin
                cnt <= cnt + 1;
                {SR, NEG_DIVISOR} <= {SR[15:0], NEG_DIVISOR[15:1]};
                if (SR[15:8] >= divisor_abs) begin
                    SR[15:8] <= SR[15:8] - divisor_abs;
                    SR[0] <= 1;
                end else begin
                    SR[0] <= 0;
                end
            end
        end else if (res_valid && res_ready) begin
            res_valid <= 0;
        end
    end

    always @(posedge clk) begin
        if (res_valid && res_ready) begin
            result <= {SR[7:0], SR[15:8]};
        end
    end

endmodule

